powershell -Command "
# PPT1 텍스트 추출
\$ppt1 = 'C:\Users\Administrator\Desktop\DL3 Lsupt\DL3 PE2 CAN 통신 신호 자료_251219.pptx'
\$tmp1 = 'C:\Users\Administrator\Desktop\DL3 Lsupt\_ppt1_extract'
if (Test-Path \$tmp1) { Remove-Item \$tmp1 -Recurse -Force }
Add-Type -AssemblyName System.IO.Compression.FileSystem
[System.IO.Compression.ZipFile]::ExtractToDirectory(\$ppt1, \$tmp1)
\$slides = Get-ChildItem \"\$tmp1\ppt\slides\" -Filter 'slide*.xml' | Sort-Object { [int](\$_.BaseName -replace 'slide','') }
foreach (\$s in \$slides) {
    [xml]\$xml = Get-Content \$s.FullName -Encoding UTF8
    \$ns = @{ a = 'http://schemas.openxmlformats.org/drawingml/2006/main' }
    \$texts = \$xml.SelectNodes('//a:t', (New-Object System.Xml.XmlNamespaceManager(\$xml.NameTable)))
    foreach (\$n in [System.Xml.XmlNamespaceManager]::new(\$xml.NameTable)) { break }
    # simpler approach
    \$allText = ([regex]::Matches((\$xml.OuterXml), '<a:t[^>]*>([^<]+)</a:t>') | ForEach-Object { \$_.Groups[1].Value }) -join '|'
    Write-Output \"=== SLIDE \$(\$s.BaseName) ===``n\$allText``n\"
}
" 2>&1

